mapper.select:
SELECT sr.*
FROM study_room sr
INNER JOIN floor f ON sr.floor_id = f.id AND f.deleted = 0
INNER JOIN building b ON f.building_id = b.id AND b.deleted = 0
INNER JOIN campus c ON b.campus_id = c.id AND c.deleted = 0

    sr.deleted = 0


        AND b.campus_id = #{query.campusId}



        AND f.building_id = #{query.buildingId}



        AND sr.floor_id = #{query.floorId}



        AND sr.room_type = #{query.roomType}



        AND sr.status = #{query.status}



        AND sr.name LIKE CONCAT('%', #{query.keyword}, '%')




        AND sr.total_seats > COALESCE(
            (SELECT COUNT(*)
             FROM seat s
             INNER JOIN reservation r ON s.id = r.seat_id
             WHERE s.room_id = sr.id
               AND s.deleted = 0
               AND r.deleted = 0
               AND r.status NOT IN ('CANCELLED', 'NO_SHOW', 'COMPLETED')
            ), 0
        )







                ORDER BY sr.name ${query.sortOrder == 'desc' ? 'DESC' : 'ASC'}


                ORDER BY sr.total_seats ${query.sortOrder == 'desc' ? 'DESC' : 'ASC'}


                ORDER BY sr.status ${query.sortOrder == 'desc' ? 'DESC' : 'ASC'}


                ORDER BY sr.updated_at ${query.sortOrder == 'desc' ? 'DESC' : 'ASC'}


                ORDER BY b.sort_order ASC, f.floor_number ASC, sr.id ASC




        ORDER BY b.sort_order ASC, f.floor_number ASC, sr.id ASC
